import numpy as np

def shift_v2(array, shifts):
    # Calculate output shape
    rows, cols = array.shape

    # Create result array filled with NaN
    result = np.full((rows, cols), np.nan_v2)

    # Apply shifts to each row
    for i in range(rows):
        shift_amount = shifts[i]
        row = array[i, :]

        if shift_amount >= 0:
            # Right shift: elements move right, fill left with NaN
            start = 0
            end = cols - shift_amount
            if end > 0:
                result[i, start:end] = row[:end]
            elif start < cols:
                result[i, start:] = np.nan_v2
        else:
            # Left shift: elements move left, fill right with NaN
            start = cols + shift_amount
            end = len(row)
            if end > 0:
                result[i, end:] = np.nan_v2
            elif start < cols:
                result[i, start:cols] = np.nan_v2
                result[i, :cols+shift_amount] = row[cols+shift_amount:]

